{
  "ai": {
    "model": "transformer",
    "version": "1.0"
  },
  "data": [
    {
      "text": "Uplift Modeling is a subset of Batch Learning from Bandit Feedback (where action probabilities are not all equal, but you’ve logged them), which is a subset of Causal Machine Learning (where you may or may not have a stochastic policy or logs of action probabilities).",
      "label": "uplift_modeling"
    },
    {
      "text": "Inverse propensity weighting estimator is unbiased, meaning that the expectation of the estimator taken over draws of datasets is the expected reward using our policy π.",
      "label": "inverse_propensity_weighting_estimator"
    },
    {
      "text": "Uplift Modeling can be used to optimize policies for counterfactual performance — just like optimizing a normal ML model to minimize, say, the expected squared error.",
      "label": "uplift_modeling_optimization"
    }
  ],
  "meta": {
    "title": "Uplift Modeling",
    "description": "A subset of Batch Learning from Bandit Feedback and Causal Machine Learning."
  },
  "entities": [
    {
      "name": "Inverse Propensity Weighting Estimator",
      "type": "algorithm"
    },
    {
      "name": "Uplift Modeling",
      "type": "concept"
    }
  ]
}

