  "quality_measurement_service": {
    "description": "Measures the precision, recall, and accuracy of each verifier.",
    "metrics": [
      {
        "name": "Precision",
        "description": "The ratio of true positives to the sum of true positives and false positives."
      },
      {
        "name": "Recall",
        "description": "The ratio of true positives to the sum of true positives and false negatives."
      },
      {
        "name": "Accuracy",
        "description": "The ratio of true positives to the sum of true positives and false positives, minus the ratio of false negatives to the sum of true positives and false negatives."
      }
    ]
  },
