{
  "ai": {
    "model": "text",
    "version": "1.0"
  },
  "data": [
    {
      "id": "1",
      "title": "Survey-based Visual Quality Signal for Pinterest's Recommender Systems",
      "description": "We present a novel approach to building a visual quality signal for Pinterest's recommender systems using survey data.",
      "text": "The problem was formulated as a pairwise ranking rather than a classification or regression problem — a well established machine learning technique to find the relative ranking of items instead of a composite score for each independent item. The idea can be simplified as: Given two images, we ask the model to predict which one the average Pinner would agree is “better,” rather than trying to predict the actual mean response score for a single image.",
      "tags": ["survey", "visual quality", "recommender systems", "Pinterest"]
    },
    {
      "id": "2",
      "title": "Offline Evaluation Results",
      "description": "We evaluated our model on a holdout test set and found that it can correctly distinguish between higher and lower content quality.",
      "text": "Quantitatively, we looked at two key metrics. The first is pairwise ranking accuracy, which measures whether the model can correctly predict which of two given images is higher quality. The second is NDCG@20, or Normalized Discounted Cumulative Gain, which measures how correctly a list of 20 images are ranked by the model scores, with more importance on the top of the list.",
      "tags": ["evaluation", "metrics", "quality"]
    },
    {
      "id": "3",
      "title": "Impact and Future Work",
      "description": "Our visual quality signal has been shown to be a win-win for both Pinners and the business across all three major user-facing surfaces at Pinterest.",
      "text": "We plan to continue building on the success we’ve found in this work. We have conducted additional similar surveys and will iterate on our model. We’ve explored leveraging state-of-the-art Visual Language Models (VLMs) that can learn more intrinsic information from the survey responses, and we are keen to productionize these in the next iteration of this signal in 2026.",
      "tags": ["impact", "future work"]
    }
  ]
}

