{
  "title": "Revolut's New Risk Framework",
  "description": "A new risk framework for Revolut, built on top of event-driven architecture and semantic reasoning.",
  "type": "article",
  "keywords": ["risk management", "event-driven architecture", "semantic reasoning"],
  "authors": [
    {
      "name": "Konstantin Vasilev",
      "title": "Risk Management Expert"
    }
  ],
  "datePublished": "2023-02-20T14:30:00.000Z",
  "dateModified": "2023-02-20T14:30:00.000Z",
  "image": {
    "url": "https://example.com/revolut-risk-framework.jpg"
  },
  "sections": [
    {
      "title": "Introduction",
      "text": "Revolut's new risk framework is built on top of event-driven architecture and semantic reasoning. This approach enables us to model complex risks in a more intuitive and flexible way."
    },
    {
      "title": "Event-Driven Architecture",
      "text": "Our risk framework is based on the concept of events, which are triggered by specific conditions or actions. Each event has a probability associated with it, allowing us to calculate the likelihood of different outcomes."
    },
    {
      "title": "Semantic Reasoning",
      "text": "We use semantic reasoning to infer logical consequences from our risk models. This enables us to identify potential risks and opportunities in a more systematic way."
    },
    {
      "title": "Implementation",
      "text": "Our implementation uses Prometheux, an explainable AI platform for big data and distributed processing. We define data models of our main concepts: State, Event, Risk, and use semantic reasoning to infer logical consequences from our risk models."
    }
  ],
  "relatedArticles": [
    {
      "title": "Revolut's New Payment System",
      "url": "https://example.com/revolut-payment-system"
    },
    {
      "title": "Risk Management in Fintech",
      "url": "https://example.com/risk-management-fintech"
    }
  ]
}

