{
  "memory_configuration_errors": {
    "description": "Memory configuration errors are generally caused by misconfiguration of job memory.",
    "challenges": [
      "Setting an excessively small memory can result in Out-Of-Memory (OOM) errors",
      "Setting an excessively large memory can waste cluster memory resources",
      "Some memory configuration errors require changing the configurations of multiple parameters"
    ]
  },
  "unclassified_errors": {
    "description": "Unclassified errors are those that cannot be recognized by the rule-based classifier.",
    "challenges": [
      "The rule-based classifier relies on data platform engineers to manually add rules for recognizing errors",
      "Adding new rules requires engineering efforts and depends on the deployment cycle"
    ]
  },
  "auto_remediation": {
    "description": "Auto remediation is a service that integrates the rule-based classifier with an ML service to generate recommendations.",
    "components": [
      "Rule Execution Engine: responsible for matching collected logs against predefined rules",
      "Result Finalizer: responsible for finalizing error classification results based on matched rules",
      "Nightingale: an ML service that generates retry recommendations",
      "ConfigService: an online configuration service that applies recommended configurations"
    ]
  },
  "ml_service": {
    "description": "The ML service, i.e., Nightingale, aims to generate a retry policy for a failed job.",
    "components": [
      "Prediction Model: jointly estimates probability of retry success and retry cost",
      "Optimizer: explores the Spark configuration parameter space to recommend a configuration"
    ]
  },
  "service_integrations": {
    "description": "The services generating and applying recommendations are decoupled.",
    "services": [
      "Pensive: an error classification service that leverages the rule-based classifier",
      "Scheduler: a service scheduling jobs (our current implementation is with Netflix Maestro)"
    ]
  }
}

