      "name": "DeepRank (formerly BERT)",
      "description": "A system that uses deep learning techniques to improve the accuracy of document ranking."
    }
  ],
  "data_storage": [
    {
      "name": "HiveMind",
      "description": "The main memory where documents and signals are stored. It is a vast network of interconnected clusters that allows millions of main memory units to work together."
    },
    {
      "name": "TeraGoogle",
      "description": "A long-term storage system for information that doesn't require quick access. It uses conventional HDDs (hard disk drives) for storage."
    }
  ],
  "ai_involvement": [
