{
  "title": "Multi-Agent Research System",
  "description": "A multi-agent system for research tasks that uses a lead agent to coordinate subagents, each with specific research tasks.",
  "keywords": ["multi-agent", "research", "system"],
  "authors": [
    {
      "name": "John Doe",
      "affiliation": "ABC Research Institute"
    }
  ],
  "abstract": "This paper presents a multi-agent system for research tasks that uses a lead agent to coordinate subagents, each with specific research tasks. The system is designed to improve the efficiency and effectiveness of research by allowing multiple agents to work together in parallel.",
  "sections": [
    {
      "title": "Introduction",
      "text": "Research tasks often require the use of multiple tools and sources, making them time-consuming and labor-intensive. This paper presents a multi-agent system for research tasks that uses a lead agent to coordinate subagents, each with specific research tasks."
    },
    {
      "title": "Architecture Overview",
      "text": "The multi-agent system consists of a lead agent and multiple subagents. The lead agent coordinates the process by analyzing user queries, developing strategies, and spawning subagents to explore different aspects in parallel."
    },
    {
      "title": "Prompt Engineering",
      "text": "Prompt engineering is critical for improving the behavior of agents. We learned several principles for prompting agents, including thinking like your agents, teaching the orchestrator how to delegate, scaling effort to query complexity, and guiding the thinking process."
    },
    {
      "title": "Tool Design and Selection",
      "text": "Agent-tool interfaces are as critical as human-computer interfaces. We gave our agents explicit heuristics for selecting tools, including examining all available tools first, matching tool usage to user intent, searching the web for broad external exploration, and preferring specialized tools over generic ones."
    },
    {
      "title": "Evaluation",
      "text": "Evaluating multi-agent systems presents unique challenges. We used flexible evaluation methods that judge whether agents achieved the right outcomes while also following a reasonable process."
    }
  ]
}

