{
  "title": "Grammarly's Architecture for Managing Suggestions",
  "text": "Grammarly uses Deltas to represent text changes produced by Grammarly suggestions. Deltas are also used to represent the user's edits and the text itself.",
  "suggestions": [
    {
      "id": 1,
      "type": "spelling correction",
      "target": "shock"
    },
    {
      "id": 2,
      "type": "rephrasing",
      "target": "The supply schock"
    }
  ],
  "architecture": [
    {
      "name": "Suggestions Repository",
      "description": "Stores all suggestions received from the back-end."
    },
    {
      "name": "Delta Manager",
      "description": "Rebases suggestion Deltas according to new changes coming in."
    },
    {
      "name": "Highlights Manager",
      "description": "Correctly highlights mistakes in the text."
    }
  ],
  "rebase procedure": [
    {
      "step": "Iterate over both Deltas' operation lists and merge them into a new operation list.",
      "result": "A rebased Delta that points to the right target in the text."
    }
  ]
}

