{
  "title": "DataK9 Architecture",
  "description": "A description of the DataK9 architecture, including its key features, matching strategy, rule-based AI, and learning-based AI.",
  "sections": [
    {
      "title": "Key Features",
      "content": "DataK9 consumes metadata, data, context, and lineage information to determine a column's weight/score for a specific tag."
    },
    {
      "title": "Matching Strategy",
      "content": "DataK9 uses individual vs. aggregate decision-making, probabilistic decision-making, and negative scoring to determine the final decision."
    },
    {
      "title": "Rule-Based AI",
      "content": "DataK9 uses hand-crafted rules, a rule language, and an engine to define and execute rules for specific tags."
    },
    {
      "title": "Learning-Based AI",
      "content": "DataK9 uses machine learning algorithms to learn from data and improve its accuracy over time."
    }
  ]
}

